+    function findSampleById(sampleId, fallback = editorSamples[0]) {
+      return gallerySamples.find((entry) => entry.id === sampleId) || fallback;
+    }
+
+    function collectShellState() {
+      const state = {};
+      for (const shell of document.querySelectorAll("[data-shell]")) {
+        state[shell.dataset.shell] = {
+          balance: shell.dataset.balance || "balanced",
+          rail: shell.dataset.rail || "expanded"
+        };
+      }
+      return state;
+    }
+
+    function applyShellStateSnapshot(shellState) {
+      if (!shellState || typeof shellState !== "object") {
+        return;
+      }
+      for (const shell of document.querySelectorAll("[data-shell]")) {
+        const next = shellState[shell.dataset.shell];
+        if (!next) {
+          continue;
+        }
+        if (typeof next.balance === "string") {
+          shell.dataset.balance = next.balance;
+        }
+        if (typeof next.rail === "string") {
+          shell.dataset.rail = next.rail;
+        }
+        applyShellState(shell);
+      }
+    }
+
+    function collectUrlState() {
+      return {
+        sample: currentSample?.id || editorSamples[0]?.id || "",
+        spotlight: spotlightSample?.id || currentSample?.id || "",
+        galleryFilter,
+        galleryQuery,
+        source: els.input.value,
+        shells: collectShellState()
+      };
+    }
+
+    function buildStateUrl() {
+      const url = new URL(window.location.href);
+      const state = collectUrlState();
+      url.searchParams.set("sample", state.sample);
+      url.searchParams.set("spotlight", state.spotlight);
+      url.searchParams.set("filter", state.galleryFilter);
+      if (state.galleryQuery) {
+        url.searchParams.set("q", state.galleryQuery);
+      } else {
+        url.searchParams.delete("q");
+      }
+      if (state.source && state.sample && state.source !== findSampleById(state.sample, currentSample).code) {
+        url.searchParams.set("source", state.source);
+      } else {
+        url.searchParams.delete("source");
+      }
+      url.searchParams.set("shells", JSON.stringify(state.shells));
+      return url;
+    }
+
+    function syncUrlState(mode = "replace") {
+      if (suppressUrlSync) {
+        return;
+      }
+      const url = buildStateUrl();
+      const next = url.toString();
+      if (next === lastStateUrl) {
+        return;
+      }
+      lastStateUrl = next;
+      if (mode === "push") {
+        history.pushState(null, "", url);
+      } else {
+        history.replaceState(null, "", url);
+      }
+    }
+
+    function restoreUrlState() {
+      const url = new URL(window.location.href);
+      const sample = findSampleById(url.searchParams.get("sample"), editorSamples[0]);
+      const spotlight = findSampleById(url.searchParams.get("spotlight"), sample);
+      const requestedFilter = url.searchParams.get("filter");
+      const query = url.searchParams.get("q") || "";
+      const sourceOverride = url.searchParams.get("source");
+      const shellJson = url.searchParams.get("shells");
+
+      suppressUrlSync = true;
+      currentSample = sample;
+      spotlightSample = spotlight;
+      galleryFilter = galleryCategories.includes(requestedFilter) ? requestedFilter : "all";
+      galleryQuery = query;
+      els.input.value = sourceOverride || sample.code;
+      els.gallerySearch.value = query;
+
+      if (shellJson) {
+        try {
+          applyShellStateSnapshot(JSON.parse(shellJson));
+        } catch (_error) {
+          // Ignore malformed shell state and keep defaults.
+        }
+      }
+
+      suppressUrlSync = false;
+      lastStateUrl = buildStateUrl().toString();
+      history.replaceState(null, "", buildStateUrl());
+    }
